let payload = msg.payload;
if (typeof payload === 'string') {
    let trimmed = payload.trim();
    // Solo permitir JSON (objeto o array)
    if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
        return msg;
    }
    // Si es un comando (ej. "setpoint:25"), lo descartamos silenciosamente
    return null;
}
return msg; // si ya es objeto, pasa
